I think the following lines should be changed to,  so that USE_BDB= 40+ doesn't bring version 4.0 by default etc:

change:

# For specifying [40, 41, ..]+
_DB_40P=        40 ${_DB_41P}
_DB_41P=        41 ${_DB_42P}
_DB_42P=        42 ${_DB_43P}
_DB_43P=        43 ${_DB_44P}
_DB_44P=        44 ${_DB_46P}
_DB_46P=        46 ${_DB_47P}
_DB_47P=        47 ${_DB_48P}
_DB_48P=        48 ${_DB_5P}
_DB_5P=         5 ${_DB_6P}
_DB_6P=         6

to:

# For specifying [40, 41, ..]+
_DB_40P=        ${_DB_41P} 40
_DB_41P=        ${_DB_42P} 41
_DB_42P=        ${_DB_43P} 42
_DB_43P=        ${_DB_44P} 43
_DB_44P=        ${_DB_46P} 44
_DB_46P=        ${_DB_47P} 46
_DB_47P=        ${_DB_48P} 47
_DB_48P=        48 ${_DB_5P}
_DB_5P=         5 ${_DB_6P}
_DB_6P=         6

what do you think?
